// 'myButton'というidを持つ要素に対するclickとdblclickイベントの設定
let myButton = document.getElementById('myButton');

// クリックイベント
myButton.addEventListener('click', function() {
  console.log('Button was clicked');
});

// ダブルクリックイベント
myButton.addEventListener('dblclick', function() {
  console.log('Button was double-clicked');
});
// これを実行すると、ボタンをクリックすると'Button was clicked'、ダブルクリックすると'Button was double-clicked'と表示されます。

// 'myButton'というidを持つ要素に対するclickイベントの設定
let myButton = document.getElementById('myButton');
myButton.addEventListener('click', function(event) {
  console.log('Button was clicked');
  event.stopPropagation();
});
// これを実行すると、ボタンがクリックされると'Button was clicked'と表示され、そのイベントの伝播は停止します。

// 'myButton'というidを持つ要素に対する一度だけ反応するclickイベントの設定
let myButton = document.getElementById('myButton');
myButton.addEventListener('click', function() {
  console.log('Button was clicked once');
}, { once: true });
// これを実行すると、ボタンをクリックすると一度だけ'Button was clicked once'と表示されます。

// 'myForm'というidを持つ要素に対するsubmitイベントの設定
let myForm = document.getElementById('myForm');
myForm.addEventListener('submit', function(event) {
  console.log('Form submission was prevented');
  event.preventDefault();
});
// これを実行すると、フォームが送信されると'Form submission was prevented'と表示され、その送信動作はキャンセルされます。

questions.question:
idが'myButton'のボタン要素に設定されたクリックイベントのリスナーを削除するJavaScriptコードを書いてください。ただし、そのリスナーは以下のコードで設定されているとします。

function handleClick() {
  console.log('Button was clicked');
}

let myButton = document.getElementById('myButton');
myButton.addEventListener('click', handleClick);

questions.answer:
// 'myButton'というidを持つ要素に設定されたclickイベントのリスナーの削除
function handleClick() {
  console.log('Button was clicked');
}

let myButton = document.getElementById('myButton');
myButton.removeEventListener('click', handleClick);
// これを実行すると、ボタンのclickイベントに対するhandleClickリスナーが削除されます。

// 'myImage'というidを持つ要素に対するmouseoverイベントの設定
let myImage = document.getElementById('myImage');
myImage.addEventListener('mouseover', function(event) {
  console.log('Mouse over image: ' + event.target.alt);
});
// これを実行すると、画像要素にマウスを乗せるとその要素のalt属性の値が表示されます。

// ページ全体に対するkeydownイベントの設定
document.addEventListener('keydown', function(event) {
  console.log('Key pressed: ' + event.keyCode);
});
// これを実行すると、キーを押すとそのキーのキーコードが表示されます。

// ページ全体に対するtouchstartイベントの設定
document.addEventListener('touchstart', function(event) {
  console.log('Touch point: ' + event.touches[0].clientX + ', ' + event.touches[0].clientY);
});
// これを実行すると、スクリーンをタッチするとそのタッチ点の座標が表示されます。

// カスタムイベント'myEvent'の作成と発火
let myEvent = new Event('myEvent');

// myEventのリスナー設定
document.addEventListener('myEvent', function() {
  console.log('Custom event fired');
});

// myEventの発火
document.dispatchEvent(myEvent);
// これを実行すると、'Custom event fired'と表示されます。

// 'myButton'というidを持つ要素に対するclickイベントの設定
let myButton = document.getElementById('myButton');
myButton.addEventListener('click', function(event) {
  console.log('Button id: ' + event.target.id);
});
// これを実行すると、ボタンをクリックするとそのボタンのidが表示されます。
